#include <stdlib.h>
#include <stdio.h>
#include <math.h>
#include <sys/time.h>
#include <cuda.h>
#include <limits.h>
#define PI 3.1415926535897932

long M = INT_MAX;

int A = 1103515245;

int C = 12345;

const int threads_per_block = 128;

long long get_time() {
	struct timeval tv;
	gettimeofday(&tv, NULL);
	return (tv.tv_sec * 1000000) + tv.tv_usec;
}

float elapsed_time(long long start_time, long long end_time) {
        return (float) (end_time - start_time) / (1000 * 1000);
}

void check_error(cudaError e) {
     if (e != cudaSuccess) {
     	printf("\nCUDA error: %s\n", cudaGetErrorString(e));
	    exit(1);
     }
}

__device__ int findIndexSeq(double * CDF, int lengthCDF, double value)
{
	int index = -1;
	int x;
	for(x = 0; x < lengthCDF; x++)
	{
		if(CDF[x] >= value)
		{
			index = x;
			break;
		}
	}
	if(index == -1)
		return lengthCDF-1;
	return index;
}

__device__ int findIndexBin(double * CDF, int beginIndex, int endIndex, double value)
{
	if(endIndex < beginIndex)
		return -1;
	int middleIndex;
	while(endIndex > beginIndex)
	{
		middleIndex = beginIndex + ((endIndex-beginIndex)/2);
		if(CDF[middleIndex] >= value)
		{
			if(middleIndex == 0)
				return middleIndex;
			else if(CDF[middleIndex-1] < value)
				return middleIndex;
			else if(CDF[middleIndex-1] == value)
			{
				while(CDF[middleIndex] == value && middleIndex >= 0)
					middleIndex--;
				middleIndex++;
				return middleIndex;
			}
		}
		if(CDF[middleIndex] > value)
			endIndex = middleIndex-1;
		else
			beginIndex = middleIndex+1;
	}
	return -1;
}

__global__ void kernel(double * arrayX, double * arrayY, double * CDF, double * u, double * xj, double * yj, int Nparticles){
	int block_id = blockIdx.x;
	int i = blockDim.x * block_id + threadIdx.x;

	if(i < Nparticles){

		int index = -1;
		int x;

		for(x = 0; x < Nparticles; x++){
			if(CDF[x] >= u[i]){
				index = x;
				break;
			}
		}
		if(index == -1){
			index = Nparticles-1;
		}

		xj[i] = arrayX[index];
		yj[i] = arrayY[index];

	}
}

double roundDouble(double value){
	int newValue = (int)(value);
	if(value - newValue < .5)
	return newValue;
	else
	return newValue++;
}

void setIf(int testValue, int newValue, int * array3D, int * dimX, int * dimY, int * dimZ){
	int x, y, z;
	for(x = 0; x < *dimX; x++){
		for(y = 0; y < *dimY; y++){
			for(z = 0; z < *dimZ; z++){
				if(array3D[x * *dimY * *dimZ+y * *dimZ + z] == testValue)
				array3D[x * *dimY * *dimZ + y * *dimZ + z] = newValue;
			}
		}
	}
}

double randu(int * seed, int index)
{
	int num = A*seed[index] + C;
	seed[index] = num % M;
	return fabs(seed[index]/((double) M));
}

double randn(int * seed, int index){

	double u = randu(seed, index);
	double v = randu(seed, index);
	double cosine = cos(2*PI*v);
	double rt = -2*log(u);
	return sqrt(rt)*cosine;
}

void addNoise(int * array3D, int * dimX, int * dimY, int * dimZ, int * seed){
	int x, y, z;
	for(x = 0; x < *dimX; x++){
		for(y = 0; y < *dimY; y++){
			for(z = 0; z < *dimZ; z++){
				array3D[x * *dimY * *dimZ + y * *dimZ + z] = array3D[x * *dimY * *dimZ + y * *dimZ + z] + (int)(5*randn(seed, 0));
			}
		}
	}
}

void strelDisk(int * disk, int radius)
{
	int diameter = radius*2 - 1;
	int x, y;
	for(x = 0; x < diameter; x++){
		for(y = 0; y < diameter; y++){
			double distance = sqrt(pow((double)(x-radius+1),2) + pow((double)(y-radius+1),2));
			if(distance < radius)
			disk[x*diameter + y] = 1;
		}
	}
}

void dilate_matrix(int * matrix, int posX, int posY, int posZ, int dimX, int dimY, int dimZ, int error)
{
	int startX = posX - error;
	while(startX < 0)
	startX++;
	int startY = posY - error;
	while(startY < 0)
	startY++;
	int endX = posX + error;
	while(endX > dimX)
	endX--;
	int endY = posY + error;
	while(endY > dimY)
	endY--;
	int x,y;
	for(x = startX; x < endX; x++){
		for(y = startY; y < endY; y++){
			double distance = sqrt( pow((double)(x-posX),2) + pow((double)(y-posY),2) );
			if(distance < error)
			matrix[x*dimY*dimZ + y*dimZ + posZ] = 1;
		}
	}
}

void imdilate_disk(int * matrix, int dimX, int dimY, int dimZ, int error, int * newMatrix)
{
	int x, y, z;
	for(z = 0; z < dimZ; z++){
		for(x = 0; x < dimX; x++){
			for(y = 0; y < dimY; y++){
				if(matrix[x*dimY*dimZ + y*dimZ + z] == 1){
					dilate_matrix(newMatrix, x, y, z, dimX, dimY, dimZ, error);
				}
			}
		}
	}
}

void getneighbors(int * se, int numOnes, double * neighbors, int radius){
	int x, y;
	int neighY = 0;
	int center = radius - 1;
	int diameter = radius*2 -1;
	for(x = 0; x < diameter; x++){
		for(y = 0; y < diameter; y++){
			if(se[x*diameter + y]){
				neighbors[neighY*2] = (int)(y - center);
				neighbors[neighY*2 + 1] = (int)(x - center);
				neighY++;
			}
		}
	}
}

void videoSequence(int * I, int IszX, int IszY, int Nfr, int * seed){
	int k;
	int max_size = IszX*IszY*Nfr;

	int x0 = (int)roundDouble(IszY/2.0);
	int y0 = (int)roundDouble(IszX/2.0);
	I[x0 *IszY *Nfr + y0 * Nfr  + 0] = 1;

	int xk, yk, pos;
	for(k = 1; k < Nfr; k++){
		xk = abs(x0 + (k-1));
		yk = abs(y0 - 2*(k-1));
		pos = yk * IszY * Nfr + xk *Nfr + k;
		if(pos >= max_size)
		pos = 0;
		I[pos] = 1;
	}

	int * newMatrix = (int *)malloc(sizeof(int)*IszX*IszY*Nfr);
	imdilate_disk(I, IszX, IszY, Nfr, 5, newMatrix);
	int x, y;
	for(x = 0; x < IszX; x++){
		for(y = 0; y < IszY; y++){
			for(k = 0; k < Nfr; k++){
				I[x*IszY*Nfr + y*Nfr + k] = newMatrix[x*IszY*Nfr + y*Nfr + k];
			}
		}
	}
	free(newMatrix);

	setIf(0, 100, I, &IszX, &IszY, &Nfr);
	setIf(1, 228, I, &IszX, &IszY, &Nfr);

	addNoise(I, &IszX, &IszY, &Nfr, seed);
}

double calcLikelihoodSum(int * I, int * ind, int numOnes){
	double likelihoodSum = 0.0;
	int y;
	for(y = 0; y < numOnes; y++)
	likelihoodSum += (pow((double)(I[ind[y]] - 100),2) - pow((double)(I[ind[y]]-228),2))/50.0;
	return likelihoodSum;
}

int findIndex(double * CDF, int lengthCDF, double value){
	int index = -1;
	int x;
	for(x = 0; x < lengthCDF; x++){
		if(CDF[x] >= value){
			index = x;
			break;
		}
	}
	if(index == -1){
		return lengthCDF-1;
	}
	return index;
}

__global__ void init_weights_kernel(double * weights, int Nparticles){
	int i = blockIdx.x * blockDim.x + threadIdx.x;
	if(i < Nparticles){
		weights[i] = 1/((double)(Nparticles));
	}
}

__global__ void init_arrays_kernel(double * arrayX, double * arrayY, double xe, double ye, int Nparticles){
	int i = blockIdx.x * blockDim.x + threadIdx.x;
	if(i < Nparticles){
		arrayX[i] = xe;
		arrayY[i] = ye;
	}
}

__global__ void update_positions_kernel(double * arrayX, double * arrayY, int * seed, int Nparticles){
	int i = blockIdx.x * blockDim.x + threadIdx.x;
	if(i < Nparticles){
		arrayX[i] += 1 + 5*randn(seed, i);
		arrayY[i] += -2 + 2*randn(seed, i);
	}
}

__global__ void calc_likelihood_kernel(double * likelihood, int * I, double * arrayX, double * arrayY, double * objxy, int * ind, int Nparticles, int countOnes, int IszY, int Nfr, int max_size, int k){
	int x = blockIdx.x * blockDim.x + threadIdx.x;
	if(x < Nparticles){
		int indX, indY;
		for(int y = 0; y < countOnes; y++){
			indX = roundDouble(arrayX[x]) + objxy[y*2 + 1];
			indY = roundDouble(arrayY[x]) + objxy[y*2];
			ind[x*countOnes + y] = fabs(indX*IszY*Nfr + indY*Nfr + k);
			if(ind[x*countOnes + y] >= max_size)
				ind[x*countOnes + y] = 0;
		}
		likelihood[x] = 0;
		for(int y = 0; y < countOnes; y++)
			likelihood[x] += (pow((I[ind[x*countOnes + y]] - 100),2) - pow((I[ind[x*countOnes + y]]-228),2))/50.0;
		likelihood[x] = likelihood[x]/((double) countOnes);
	}
}

__global__ void exp_weights_kernel(double * weights, double * likelihood, int Nparticles){
	int i = blockIdx.x * blockDim.x + threadIdx.x;
	if(i < Nparticles){
		weights[i] = weights[i] * exp(likelihood[i]);
	}
}

__global__ void sum_weights_kernel(double * weights, double * sumWeights, int Nparticles){
	int i = blockIdx.x * blockDim.x + threadIdx.x;
	if(i < Nparticles){
		*sumWeights += weights[i];
	}
}

__global__ void normalize_weights_kernel(double * weights, double sumWeights, int Nparticles){
	int i = blockIdx.x * blockDim.x + threadIdx.x;
	if(i < Nparticles){
		weights[i] = weights[i]/sumWeights;
	}
}

__global__ void calc_xe_ye_kernel(double * arrayX, double * arrayY, double * weights, double * xe, double * ye, int Nparticles){
	int i = blockIdx.x * blockDim.x + threadIdx.x;
	if(i < Nparticles){
		*xe += arrayX[i] * weights[i];
		*ye += arrayY[i] * weights[i];
	}
}

__global__ void calc_CDF_kernel(double * CDF, double * weights, int Nparticles){
	int i = blockIdx.x * blockDim.x + threadIdx.x;
	if(i == 0){
		CDF[0] = weights[0];
	}
	if(i > 0 && i < Nparticles){
		CDF[i] = weights[i] + CDF[i-1];
	}
}

__global__ void calc_u_kernel(double * u, double u1, int Nparticles){
	int i = blockIdx.x * blockDim.x + threadIdx.x;
	if(i < Nparticles){
		u[i] = u1 + i/((double)(Nparticles));
	}
}

__global__ void resample_kernel(double * CDF, double * arrayX, double * arrayY, double * u, double * xj, double * yj, int Nparticles){
	int j = blockIdx.x * blockDim.x + threadIdx.x;
	if(j < Nparticles){
		int i = findIndexSeq(CDF, Nparticles, u[j]);
		if(i == -1)
			i = Nparticles-1;
		xj[j] = arrayX[i];
		yj[j] = arrayY[i];
	}
}

__global__ void reset_kernel(double * arrayX, double * arrayY, double * xj, double * yj, double * weights, int Nparticles){
	int i = blockIdx.x * blockDim.x + threadIdx.x;
	if(i < Nparticles){
		arrayX[i] = xj[i];
		arrayY[i] = yj[i];
		weights[i] = 1/((double)(Nparticles));
	}
}

void particleFilter(int * I, int IszX, int IszY, int Nfr, int * seed, int Nparticles){

	int max_size = IszX*IszY*Nfr;
	long long start = get_time();

	double xe = roundDouble(IszY/2.0);
	double ye = roundDouble(IszX/2.0);

	int radius = 5;
	int diameter = radius*2 - 1;
	int * disk = (int *)malloc(diameter*diameter*sizeof(int));
	strelDisk(disk, radius);
	int countOnes = 0;
	int x, y;
	for(x = 0; x < diameter; x++){
		for(y = 0; y < diameter; y++){
			if(disk[x*diameter + y] == 1)
				countOnes++;
		}
	}
	double * objxy = (double *)malloc(countOnes*2*sizeof(double));
	getneighbors(disk, countOnes, objxy, radius);

	long long get_neighbors = get_time();
	printf("TIME TO GET NEIGHBORS TOOK: %f\n", elapsed_time(start, get_neighbors));

	double * weights;
	double * likelihood;
	double * arrayX;
	double * arrayY;
	double * xj;
	double * yj;
	double * CDF;
	double * u;
	int * ind;

	check_error(cudaMalloc((void**)&weights, sizeof(double)*Nparticles));
	check_error(cudaMalloc((void**)&likelihood, sizeof(double)*Nparticles));
	check_error(cudaMalloc((void**)&arrayX, sizeof(double)*Nparticles));
	check_error(cudaMalloc((void**)&arrayY, sizeof(double)*Nparticles));
	check_error(cudaMalloc((void**)&xj, sizeof(double)*Nparticles));
	check_error(cudaMalloc((void**)&yj, sizeof(double)*Nparticles));
	check_error(cudaMalloc((void**)&CDF, sizeof(double)*Nparticles));
	check_error(cudaMalloc((void**)&u, sizeof(double)*Nparticles));
	check_error(cudaMalloc((void**)&ind, sizeof(int)*countOnes*Nparticles));

	int num_blocks = ceil((double)Nparticles/(double)threads_per_block);

	init_weights_kernel<<<num_blocks, threads_per_block>>>(weights, Nparticles);
	cudaDeviceSynchronize();
	long long get_weights = get_time();
	printf("TIME TO GET WEIGHTSTOOK: %f\n", elapsed_time(get_neighbors, get_weights));

	init_arrays_kernel<<<num_blocks, threads_per_block>>>(arrayX, arrayY, xe, ye, Nparticles);
	cudaDeviceSynchronize();

	printf("TIME TO SET ARRAYS TOOK: %f\n", elapsed_time(get_weights, get_time()));
	int indX, indY;
	int k;
	for(k = 1; k < Nfr; k++){
		long long set_arrays = get_time();

		update_positions_kernel<<<num_blocks, threads_per_block>>>(arrayX, arrayY, seed, Nparticles);
		cudaDeviceSynchronize();
		long long error = get_time();
		printf("TIME TO SET ERROR TOOK: %f\n", elapsed_time(set_arrays, error));

		calc_likelihood_kernel<<<num_blocks, threads_per_block>>>(likelihood, I, arrayX, arrayY, objxy, ind, Nparticles, countOnes, IszY, Nfr, max_size, k);
		cudaDeviceSynchronize();
		long long likelihood_time = get_time();
		printf("TIME TO GET LIKELIHOODS TOOK: %f\n", elapsed_time(error, likelihood_time));

		exp_weights_kernel<<<num_blocks, threads_per_block>>>(weights, likelihood, Nparticles);
		cudaDeviceSynchronize();
		long long exponential = get_time();
		printf("TIME TO GET EXP TOOK: %f\n", elapsed_time(likelihood_time, exponential));

		double * sumWeights_gpu;
		check_error(cudaMalloc((void**)&sumWeights_gpu, sizeof(double)));
		*sumWeights_gpu = 0;
		sum_weights_kernel<<<num_blocks, threads_per_block>>>(weights, sumWeights_gpu, Nparticles);
		cudaDeviceSynchronize();
		double sumWeights;
		cudaMemcpy(&sumWeights, sumWeights_gpu, sizeof(double), cudaMemcpyDeviceToHost);
		cudaFree(sumWeights_gpu);
		long long sum_time = get_time();
		printf("TIME TO SUM WEIGHTS TOOK: %f\n", elapsed_time(exponential, sum_time));

		normalize_weights_kernel<<<num_blocks, threads_per_block>>>(weights, sumWeights, Nparticles);
		cudaDeviceSynchronize();
		long long normalize = get_time();
		printf("TIME TO NORMALIZE WEIGHTS TOOK: %f\n", elapsed_time(sum_time, normalize));

		double * xe_gpu, * ye_gpu;
		check_error(cudaMalloc((void**)&xe_gpu, sizeof(double)));
		check_error(cudaMalloc((void**)&ye_gpu, sizeof(double)));
		*xe_gpu = 0;
		*ye_gpu = 0;
		calc_xe_ye_kernel<<<num_blocks, threads_per_block>>>(arrayX, arrayY, weights, xe_gpu, ye_gpu, Nparticles);
		cudaDeviceSynchronize();
		cudaMemcpy(&xe, xe_gpu, sizeof(double), cudaMemcpyDeviceToHost);
		cudaMemcpy(&ye, ye_gpu, sizeof(double), cudaMemcpyDeviceToHost);
		cudaFree(xe_gpu);
		cudaFree(ye_gpu);
		long long move_time = get_time();
		printf("TIME TO MOVE OBJECT TOOK: %f\n", elapsed_time(normalize, move_time));
		printf("XE: %lf\n", xe);
		printf("YE: %lf\n", ye);
		double distance = sqrt( pow((double)(xe-(int)roundDouble(IszY/2.0)),2) + pow((double)(ye-(int)roundDouble(IszX/2.0)),2) );
		printf("%lf\n", distance);

		calc_CDF_kernel<<<num_blocks, threads_per_block>>>(CDF, weights, Nparticles);
		cudaDeviceSynchronize();
		long long cum_sum = get_time();
		printf("TIME TO CALC CUM SUM TOOK: %f\n", elapsed_time(move_time, cum_sum));

		double u1 = (1/((double)(Nparticles)))*randu(seed, 0);
		calc_u_kernel<<<num_blocks, threads_per_block>>>(u, u1, Nparticles);
		cudaDeviceSynchronize();
		long long u_time = get_time();
		printf("TIME TO CALC U TOOK: %f\n", elapsed_time(cum_sum, u_time));

		resample_kernel<<<num_blocks, threads_per_block>>>(CDF, arrayX, arrayY, u, xj, yj, Nparticles);
		cudaDeviceSynchronize();
		long long xyj_time = get_time();
		printf("TIME TO CALC NEW ARRAY X AND Y TOOK: %f\n", elapsed_time(u_time, xyj_time));

		reset_kernel<<<num_blocks, threads_per_block>>>(arrayX, arrayY, xj, yj, weights, Nparticles);
		cudaDeviceSynchronize();
		long long reset = get_time();
		printf("TIME TO RESET WEIGHTS TOOK: %f\n", elapsed_time(xyj_time, reset));
	}

	cudaFree(weights);
	cudaFree(likelihood);
	cudaFree(arrayX);
	cudaFree(arrayY);
	cudaFree(xj);
	cudaFree(yj);
	cudaFree(CDF);
	cudaFree(u);
	cudaFree(ind);

	free(disk);
	free(objxy);
}

int main(int argc, char * argv[]){

	char* usage = "openmp.out -x <dimX> -y <dimY> -z <Nfr> -np <Nparticles>";

	if(argc != 9)
	{
		printf("%s\n", usage);
		return 0;
	}

	if( strcmp( argv[1], "-x" ) ||  strcmp( argv[3], "-y" ) || strcmp( argv[5], "-z" ) || strcmp( argv[7], "-np" ) ) {
		printf( "%s\n",usage );
		return 0;
	}

	int IszX, IszY, Nfr, Nparticles;

	if( sscanf( argv[2], "%d", &IszX ) == EOF ) {
	   printf("ERROR: dimX input is incorrect");
	   return 0;
	}

	if( IszX <= 0 ) {
		printf("dimX must be > 0\n");
		return 0;
	}

	if( sscanf( argv[4], "%d", &IszY ) == EOF ) {
	   printf("ERROR: dimY input is incorrect");
	   return 0;
	}

	if( IszY <= 0 ) {
		printf("dimY must be > 0\n");
		return 0;
	}

	if( sscanf( argv[6], "%d", &Nfr ) == EOF ) {
	   printf("ERROR: Number of frames input is incorrect");
	   return 0;
	}

	if( Nfr <= 0 ) {
		printf("number of frames must be > 0\n");
		return 0;
	}

	if( sscanf( argv[8], "%d", &Nparticles ) == EOF ) {
	   printf("ERROR: Number of particles input is incorrect");
	   return 0;
	}

	if( Nparticles <= 0 ) {
		printf("Number of particles must be > 0\n");
		return 0;
	}

	int * seed = (int *)malloc(sizeof(int)*Nparticles);
	int i;
	for(i = 0; i < Nparticles; i++)
		seed[i] = time(0)*i;

	int * I = (int *)malloc(sizeof(int)*IszX*IszY*Nfr);
	long long start = get_time();

	videoSequence(I, IszX, IszY, Nfr, seed);
	long long endVideoSequence = get_time();
	printf("VIDEO SEQUENCE TOOK %f\n", elapsed_time(start, endVideoSequence));

	particleFilter(I, IszX, IszY, Nfr, seed, Nparticles);
	long long endParticleFilter = get_time();
	printf("PARTICLE FILTER TOOK %f\n", elapsed_time(endVideoSequence, endParticleFilter));
	printf("ENTIRE PROGRAM TOOK %f\n", elapsed_time(start, endParticleFilter));

	free(seed);
	free(I);
	return 0;
}
